import os
import json
from google.cloud import storage

class ModelLoader:
    def __init__(self, model_path):
        self.model_path = model_path
        self.storage_client = storage.Client()

    def load_model(self):
        bucket_name = os.environ['MODEL_BUCKET']
        blob = self.storage_client.bucket(bucket_name).blob(self.model_path)
        model = json.loads(blob.download_as_string())
        return model